mapper.select:
SELECT s.id, s.name, s.subtitle, s.cover_url, s.rating, s.rating_count, s.price_text, s.address, s.view_count, s.favorite_count, s.comment_count, s.status, c.name as city_name FROM t_spot s LEFT JOIN t_destination_city c ON s.city_id = c.id WHERE s.deleted_flag = 0
AND s.city_id = #{query.cityId}
AND c.name LIKE CONCAT('%', #{query.cityName}, '%')
AND s.category_id = #{query.categoryId}
AND s.name LIKE CONCAT('%', #{query.name}, '%')
AND (s.name LIKE CONCAT('%', #{query.keyword}, '%') OR s.description LIKE CONCAT('%', #{query.keyword}, '%'))
AND s.rating >= #{query.minRating}
AND s.price_min >= #{query.minPrice}
AND s.price_max <= #{query.maxPrice}
AND s.status = #{query.status}
AND EXISTS (SELECT 1 FROM t_spot_tag_map m WHERE m.spot_id = s.id AND m.tag_id = #{query.tagId})
AND EXISTS ( SELECT 1 FROM t_spot_tag_map m INNER JOIN t_spot_tag t ON m.tag_id = t.id WHERE m.spot_id = s.id AND t.name = #{query.tagName} )
ORDER BY s.rating ASC DESC
ORDER BY s.view_count ASC DESC
ORDER BY s.hot_score DESC
